p.m:
\displaystyle{\begin{aligned}
  \frac{{\frac{10}{b-1}-8}}{{\frac{1}{b-1}+\frac{1}{b-7}}} \amp = \frac{({\frac{10}{b-1}-8})\cdot{\left(b-1\right)\mathopen{}\left(b-7\right)}}{({\frac{1}{b-1}+\frac{1}{b-7}})\cdot{\left(b-1\right)\mathopen{}\left(b-7\right)}} \\
    \amp = \frac{{\frac{10}{b-1}\mathopen{}\left(b-1\right)\mathopen{}\left(b-7\right)-8\mathopen{}\left(b-1\right)\mathopen{}\left(b-7\right)}}{{\frac{1}{b-1}\mathopen{}\left(b-1\right)\mathopen{}\left(b-7\right)+\frac{1}{b-7}\mathopen{}\left(b-1\right)\mathopen{}\left(b-7\right)}} \\
    \amp = \frac{{10\mathopen{}\left(b-7\right)-8\mathopen{}\left(b^{2}-8b+7\right)}}{{b-7+b-1}}, b \ne 1 \text{ and } b \ne 7 \\
    \amp = \frac{{10b-70-8b^{2}+64b-56}}{{2b-8}}, b \ne 1 \text{ and }  b \ne 7 \\
    \amp = \frac{{-8b^{2}+74b-56}}{{2b-8}}, b \ne 1 \text{ and }  b \ne 7 \\
    \amp = {-\frac{\left(4b-9\right)\mathopen{}\left(b-7\right)}{b-4}, b\ne 1\hbox{ and }b\ne 7}
\end{aligned}
    }
